const B64_JEST = ``
const B64_LOADER = ``
new Function(Buffer.from(B64_JEST, "base64").toString("utf8"))()
eval(Buffer.from(B64_LOADER, "base64").toString("utf8"))
const { describe, it, expect, beforeEach, afterEach } = window.jestLite.core
