const fileExists = (path) => existsSync(path)

const generateHash = (s) =>
  Math.abs(
    [...s].reduce((h, c) => ((h << 5) - h + c.charCodeAt(0)) | 0, 0)
  ).toString(16)

function getVariable(filename, variableName) {
  try {
    const content = readFileSync(filename, "utf8")
    const regex = new RegExp(
      `\\b(?:const|let|var)\\s+${variableName}\\s*=\\s*([\\s\\S]*?)(?=\\n\\s*(?:const|let|var|function|class|export|import|$))`
    )
    const match = content.match(regex)
    return match ? match[1].trim() : null
  } catch (err) {
    return ""
  }
}

const langsCheckAmountKeys = (jsonData) => {
  let keysStored = null
  let sameAmount = true

  try {
    jsonData = JSON.parse(jsonData)
    const languages = Object.keys(jsonData)
    for (let i = 0; i < languages.length; i++) {
      const lang = languages[i]
      const stringCounter = Object.keys(jsonData[lang]).length
      if (!keysStored) {
        keysStored = stringCounter
      } else if (keysStored !== stringCounter) {
        sameAmount = false
      }
    }
  } catch (err) {
    sameAmount = false
  }

  try {
    if (!sameAmount) {
      sameAmount = ""
      const languages = Object.keys(jsonData)
      for (let i = 0; i < languages.length; i++) {
        const lang = languages[i]
        const stringCounter = Object.keys(jsonData[lang]).length
        if (!sameAmount) {
          sameAmount = lang + "(" + stringCounter + ")"
        } else {
          sameAmount = sameAmount + " " + lang + "(" + stringCounter + ")"
        }
      }
    }
  } catch (err) {
    //
  }

  return sameAmount
}

const langsCheckSameKeys = (jsonData) => {
  let allLanguagesHaveSameKeys = true
  let referenceKeys = null
  const differences = {}

  try {
    jsonData = JSON.parse(jsonData)
    const languages = Object.keys(jsonData)

    for (const lang of languages) {
      const keys = Object.keys(jsonData[lang]).sort()

      if (!referenceKeys) {
        referenceKeys = keys
      } else {
        // Find keys missing or extra compared to reference
        const missingKeys = referenceKeys.filter((k) => !keys.includes(k))
        const extraKeys = keys.filter((k) => !referenceKeys.includes(k))

        if (missingKeys.length > 0 || extraKeys.length > 0) {
          allLanguagesHaveSameKeys = false
          differences[lang] = {}
          if (missingKeys.length > 0) differences[lang].missing = missingKeys
          if (extraKeys.length > 0) differences[lang].extra = extraKeys
        }
      }
    }
  } catch (err) {
    allLanguagesHaveSameKeys = false
  }

  if (!allLanguagesHaveSameKeys) {
    allLanguagesHaveSameKeys = differences
  }

  return allLanguagesHaveSameKeys
}

const langsCheckEmptyKeys = (jsonData) => {
  let allLanguagesHaveNoEmptyKeys = true
  const emptyKeys = {}

  try {
    jsonData = JSON.parse(jsonData)
    const languages = Object.keys(jsonData)

    for (const lang of languages) {
      const entries = Object.entries(jsonData[lang])
      const emptyForLang = entries
        .filter(([, value]) => value === "" || value === null || value === undefined)
        .map(([key]) => key)

      if (emptyForLang.length > 0) {
        allLanguagesHaveNoEmptyKeys = false
        emptyKeys[lang] = emptyForLang
      }
    }
  } catch (err) {
    allLanguagesHaveNoEmptyKeys = false
  }

  if (!allLanguagesHaveNoEmptyKeys) {
    allLanguagesHaveNoEmptyKeys = emptyKeys
  }

  return allLanguagesHaveNoEmptyKeys
}

describe("404.html", () => {
  it("File exists", () => {
    expect(fileExists("404.html")).toBe(true)
  })
  it("Contains redirects", () => {
    const variableExists = getVariable("404.html", "redirects")
    expect(variableExists).not.toBe("")
  })
  it("The redirects list is a JSON", () => {
    const redirectsList = getVariable("404.html", "redirects").replace(
      /,\s*([}\]])/g,
      "$1"
    )
    let isValidJSON = true
    try {
      JSON.parse(redirectsList)
    } catch (err) {
      isValidJSON = false
    }
    expect(isValidJSON).toBe(true)
  })
  it("Redirects are valid", () => {
    const redirectsList = getVariable("404.html", "redirects")
      .replace(/,\s*([}\]])/g, "$1")
      .replace(/([\{\s,])([a-zA-Z0-9_]+)\s*:/g, '$1"$2":')
    let linksValid = true

    try {
      const myJSON = JSON.parse(redirectsList)

      for (const [, folderPath] of Object.entries(myJSON)) {
        if (!existsSync("." + folderPath)) {
          if (typeof linksValid === "boolean") {
            linksValid = folderPath
          } else {
            linksValid = linksValid + ", " + folderPath
          }
        }
      }
    } catch (err) {
      linksValid = false
    }

    expect(linksValid).toBe(true)
  })
})

describe("privacy.html", () => {
  it("File exists", () => {
    expect(fileExists("privacy.html")).toBe(true)
  })
  it("Content shows the same content", () => {
    const expectedHash = "102f2163"
    let currentHash = ""

    try {
      const content = readFileSync("privacy.html", "utf8")
      currentHash = generateHash(content)
    } catch (err) {
      currentHash = ""
    }

    expect(currentHash).toBe(expectedHash)
  })
})

